update spark_bot
set floated = 0
where user_id = #{uid}

    and id != #{excludeId}

mapper.select:
select * from spark_bot sb where sb.deleted = 0 and sb.user_id = #{uid}


    and (POSITION(#{content} IN sb.name) > 0 or POSITION(#{content} IN sb.description) > 0)

order by sb.update_time desc

select * from spark_bot sb


        and sb.id not in

            #{id}



        and (POSITION(#{content} IN sb.name) > 0 or POSITION(#{content} IN sb.description) > 0)


        and sb.bot_tag LIKE CONCAT('%', #{tags}, '%')



            and sb.id in

                #{id}



            and (
            sb.is_public = 1

                or sb.user_id = #{adminUid}

            )


    and sb.deleted = 0


      order by sb.top desc, sb.favorite_count desc,sb.update_time desc,sb.name desc
      order by sb.top desc, sb.update_time desc,sb.favorite_count desc,sb.name desc

        order by

        sb.update_time desc



    LIMIT #{limit}
     OFFSET #{start}

SELECT x.* FROM spark_bot x

    x.deleted = 0
    and x.public_id = #{botId}
    and x.user_id = #{userId}

select * from spark_bot sb

    (
    user_id = #{userId}

        or sb.id in

            #{id}


    )

        and (POSITION(#{content} IN sb.name) > 0 or POSITION(#{content} IN sb.description) > 0)

    and sb.deleted = 0

order by sb.update_time desc
